/**
 * Model User
 * A facilitator or Super Admin account. Maps 1:1 to a Supabase Auth user
 * via `authId` (the Supabase `auth.users.id` UUID) — Prisma does not manage
 * authentication itself, only application-level profile/role data.
 */
export type User = $Result.DefaultSelection<Prisma.$UserPayload>
/**
 * Model Batch
 * A cohort/term, e.g. "MDC Batch 12" or "CC Batch 3 - 2026". Batches scope
 * classes to a specific run of the program so history isn't overwritten
 * year to year.
 */
export type Batch = $Result.DefaultSelection<Prisma.$BatchPayload>
/**
 * Model Week
 * A single week within a Batch's weekly cycle (e.g. "Week 1"). Deliberately
 * a lightweight, self-contained checklist for Phase 7 — it does NOT link to
 * Attendance/Activity/PAActivity from Phase 2; each item here is just a
 * simple completion flag/score. Wiring Week to the real grading tables is
 * a later-phase decision once that workflow is designed.
 */
export type Week = $Result.DefaultSelection<Prisma.$WeekPayload>
/**
 * Model Class
 * A single class/section within a Batch, run by one facilitator.
 * This is the primary unit facilitators interact with day to day.
 */
export type Class = $Result.DefaultSelection<Prisma.$ClassPayload>
/**
 * Model Group
 * A small group within a Class (used for group-based activities and
 * GroupChip tracking). A student belongs to at most one group per class.
 */
export type Group = $Result.DefaultSelection<Prisma.$GroupPayload>
/**
 * Model Student
 * Students never log in — this is pure profile/roster data scoped to a
 * single Class (re-enrollment in a new Batch/Class creates a new record,
 * keeping each term's data independent and auditable).
 */
export type Student = $Result.DefaultSelection<Prisma.$StudentPayload>
/**
 * Model Attendance
 * One attendance-taking session for a Class (e.g. a specific date/week).
 * Kept separate from AttendanceRecord so a session's metadata (date,
 * topic) isn't duplicated per student.
 */
export type Attendance = $Result.DefaultSelection<Prisma.$AttendancePayload>
/**
 * Model AttendanceRecord
 * A single student's attendance status for one Attendance session.
 * Normalized out of Attendance so each student's status, not just the
 * session, can be queried/updated independently.
 */
export type AttendanceRecord = $Result.DefaultSelection<Prisma.$AttendanceRecordPayload>
/**
 * Model GradeCategory
 * A weighted grading category within a Class (e.g. "Quizzes", "Participation").
 * Weights are configured per class, referencing global defaults in Settings.
 */
export type GradeCategory = $Result.DefaultSelection<Prisma.$GradeCategoryPayload>
/**
 * Model Activity
 * A single gradable item within a GradeCategory (e.g. "Quiz 1").
 */
export type Activity = $Result.DefaultSelection<Prisma.$ActivityPayload>
/**
 * Model ActivityScore
 * A single student's score on a single Activity. The optional
 * `overriddenById` records which Super Admin manually corrected a score
 * after the record was locked, satisfying the audit requirement.
 */
export type ActivityScore = $Result.DefaultSelection<Prisma.$ActivityScorePayload>
/**
 * Model PAActivity
 * A separate gradable-item type from Activity, representing Participation
 * Assessment style activities. Kept distinct from Activity/GradeCategory
 * since PA scoring has its own rubric shape, not weighted-category based.
 */
export type PAActivity = $Result.DefaultSelection<Prisma.$PAActivityPayload>
/**
 * Model PAScore
 * A single student's score on a single PAActivity.
 */
export type PAScore = $Result.DefaultSelection<Prisma.$PAScorePayload>
/**
 * Model GroupChip
 * A point/token awarded or deducted to a Group (e.g. gamified group
 * participation tracking). Kept as an append-only log (not a running
 * total column) so history and reasons are always auditable.
 */
export type GroupChip = $Result.DefaultSelection<Prisma.$GroupChipPayload>
/**
 * Model Demerit
 * A demerit issued to an individual Student by a facilitator.
 */
export type Demerit = $Result.DefaultSelection<Prisma.$DemeritPayload>
/**
 * Model File
 * Metadata for a file stored in Supabase Storage. Only the storage path
 * and metadata live in Postgres — actual bytes live in Supabase Storage.
 * `entityType`/`entityId` form a lightweight polymorphic association so
 * files can attach to a Student, Class, or Activity without a join
 * table per entity type.
 */
export type File = $Result.DefaultSelection<Prisma.$FilePayload>
/**
 * Model AuditLog
 * Immutable log of every important action in the system, per the
 * project's "every important action must be logged" requirement.
 * `entityType`/`entityId` again form a lightweight polymorphic link so
 * one table covers actions across all other entities.
 */
export type AuditLog = $Result.DefaultSelection<Prisma.$AuditLogPayload>
/**
 * Model UnlockLog
 * Dedicated log for the Super-Admin-only "unlock records" capability
 * (e.g. re-opening a locked Attendance session or Activity for editing).
 * Kept separate from AuditLog because unlocks carry an explicit reason,
 * which generic audit entries don't structurally require.
 */
export type UnlockLog = $Result.DefaultSelection<Prisma.$UnlockLogPayload>
/**
 * Model Settings
 * System-wide key/value configuration managed by Super Admin (e.g. default
 * grade category weights, demerit point thresholds). A single flexible
 * table rather than one column per setting, so new settings don't require
 * migrations.
 */
export type Settings = $Result.DefaultSelection<Prisma.$SettingsPayload>

